import React from 'react';
import clsx from 'clsx';
import type { ColorPickerSaturationProps } from '../components/ColorPickerSaturation';
import { ColorPickerSaturation } from '../components/ColorPickerSaturation';
import type { ColorPickerHueProps } from '../components/ColorPickerHue';
import { ColorPickerHue } from '../components/ColorPickerHue';
import { Panel } from '../components/Panel';
import { useColorPickerContext } from '../ColorPickerContext';
import { ColorPickerContainer } from '../components/ColorPickerContainer';

export interface PaletteProps
  extends React.ComponentPropsWithoutRef<'div'>,
    Pick<ColorPickerHueProps, 'onHueDragEnd'>,
    Pick<ColorPickerSaturationProps, 'onSaturationDragEnd'> {}
/**
 * ColorPicker 和 PaletteColorPicker 公用的 Palette 组件
 */
export const Palette = React.forwardRef<HTMLDivElement, PaletteProps>(
  ({ className, onHueDragEnd, onSaturationDragEnd, ...restProps }, ref) => {
    const { rootCssScope } = useColorPickerContext();

    return (
      <ColorPickerContainer className={clsx(rootCssScope('-sketch'), className)} ref={ref} {...restProps}>
        <ColorPickerSaturation onSaturationDragEnd={onSaturationDragEnd} />
        <ColorPickerHue onHueDragEnd={onHueDragEnd} />
        <Panel />
      </ColorPickerContainer>
    );
  },
);
